"""Script to generate legal_knowledge_base.json"""
import json, pathlib

kb = [
  {"id":"tenancy_001","category":"tenancy_law","title":"Security Deposit Norms","text":"In India, security deposits for residential rental agreements typically range from 2 to 3 months rent. Under the Model Tenancy Act 2021, the maximum permissible security deposit for residential premises is 2 months rent, and for non-residential premises it is 6 months advance. Demanding more than 3 months is above the standard norm. The landlord must return the full security deposit within 1 month of the tenant vacating, after making only documented deductions for damages beyond normal wear and tear. Failure to return within this period makes the landlord liable to pay interest.","act_name":"Model Tenancy Act 2021","act_section":"Section 11","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"medium"},
  {"id":"tenancy_002","category":"tenancy_law","title":"Lock-in Period Norms","text":"In India, the standard and most common lock-in period for residential rental agreements is 11 months. Agreements of 12 months or more require mandatory registration under the Registration Act 1908, involving stamp duty and registration fees. Lock-in periods exceeding 11 months are uncommon for residential rentals. A 24 or 36 month lock-in clause is significantly above the standard norm and places considerable financial burden on the tenant, who may face full remaining rent liability if they need to vacate early.","act_name":"Registration Act 1908","act_section":"Section 17","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"high"},
  {"id":"tenancy_003","category":"tenancy_law","title":"Notice Period Requirements","text":"For residential rental agreements in India, the standard notice period for termination is typically 1 month (30 days). Under the Model Tenancy Act 2021, the required notice period for termination of a periodic tenancy is one rental period or one month, whichever is less. Notice periods exceeding 2 months are above the general standard. Any clause requiring a longer notice period from the tenant than from the landlord creates asymmetric obligation. Notice must be given in writing to be legally enforceable.","act_name":"Model Tenancy Act 2021","act_section":"Section 21","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"medium"},
  {"id":"tenancy_004","category":"tenancy_law","title":"Rent Increase Clauses","text":"A standard rent increase provision typically allows for a 5 to 10 percent annual increase. Under the Model Tenancy Act 2021, any increase in rent is permissible but must be as per the terms agreed in the tenancy agreement. Clauses allowing rent increases greater than 10 percent per year or more frequently than once per year are considered aggressive. Any rent increase must be communicated in writing with at least 3 months notice before the increase takes effect.","act_name":"Model Tenancy Act 2021","act_section":"Section 8","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"medium"},
  {"id":"tenancy_005","category":"tenancy_law","title":"Landlord Right to Enter Premises","text":"Under the Model Tenancy Act 2021, the landlord must give the tenant at least 24 hours written notice before entering the premises for inspection or repairs. Entry is permitted only at reasonable times, typically during daytime hours. Clauses granting the landlord unrestricted right of entry at any time without notice violate the tenant's right to peaceful enjoyment of the property and are considered overly invasive.","act_name":"Model Tenancy Act 2021","act_section":"Section 19","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"high"},
  {"id":"tenancy_006","category":"tenancy_law","title":"Subletting Rules","text":"In India, a tenant generally cannot sublet the rented premises to another person without the explicit written consent of the landlord. Doing so without permission can be grounds for eviction. Under the Model Tenancy Act 2021, subletting without the landlord's written consent is a breach of the tenancy agreement.","act_name":"Model Tenancy Act 2021","act_section":"Section 13","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"low"},
  {"id":"tenancy_007","category":"tenancy_law","title":"Maintenance and Repair Responsibilities","text":"Under the Model Tenancy Act 2021, the landlord is responsible for structural repairs, maintaining the property in habitable condition, ensuring water supply and sanitation, and repairing damage beyond the tenant's control. The tenant is responsible for minor day-to-day maintenance. Clauses that shift major structural repair responsibilities to the tenant are unusual and potentially unfair.","act_name":"Model Tenancy Act 2021","act_section":"Section 16","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"medium"},
  {"id":"tenancy_008","category":"tenancy_law","title":"Eviction Grounds","text":"Under the Model Tenancy Act 2021, a landlord can seek eviction only on specific legal grounds including: non-payment of rent for 2 or more months, subletting without permission, misusing the premises, causing damage to the property, the landlord requiring it for personal use, and the premises being unsafe. Eviction must be carried out through the Rent Authority or court. Self-help eviction, including cutting utilities or changing locks, is illegal.","act_name":"Model Tenancy Act 2021","act_section":"Section 22","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"high"},
  {"id":"tenancy_009","category":"tenancy_law","title":"Agreement Registration Requirements","text":"In India, a rental agreement for a period of 12 months or more must be compulsorily registered under the Registration Act 1908. Agreements of less than 12 months are exempt. An unregistered agreement of 12 months or more is not admissible as evidence in court proceedings. The 11-month format is widely used specifically to avoid registration requirements and save on stamp duty.","act_name":"Registration Act 1908","act_section":"Section 17","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"low"},
  {"id":"tenancy_010","category":"tenancy_law","title":"Utility and Maintenance Charges","text":"In standard Indian rental agreements, the tenant is responsible for paying utility bills such as electricity, water, and gas. Maintenance charges for the society or building are sometimes charged to the tenant, but this should be explicitly stated in the agreement. Clauses that include vague references to additional charges without specifying the amount or calculation formula are considered risky.","act_name":"Model Tenancy Act 2021","act_section":"Section 9","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"medium"},
  {"id":"tenancy_011","category":"tenancy_law","title":"Tenant Rights to Peaceful Enjoyment","text":"Every tenant in India has the right to peaceful enjoyment of the rented property throughout the tenancy period. The landlord cannot unreasonably interfere with the tenant's use of the property. Harassment by the landlord, such as repeated unannounced visits, shutting off utilities to force eviction, threatening calls, or using agents to intimidate tenants, is illegal. Under the Model Tenancy Act 2021, tenants can approach the Rent Authority for relief against landlord harassment.","act_name":"Model Tenancy Act 2021","act_section":"Section 19","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"high"},
  {"id":"tenancy_012","category":"tenancy_law","title":"Automatic Renewal Clauses","text":"Some rental agreements include automatic renewal clauses that extend the agreement for another term if the tenant does not give notice to vacate by a specific deadline. These clauses can trap tenants into extended lock-in periods if they miss the notice window. A fair automatic renewal clause gives the tenant at least 30 days to provide notice before the renewal triggers.","act_name":"Indian Contract Act 1872","act_section":"General Contract Principles","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"high"},
  {"id":"employment_001","category":"employment_law","title":"Notice Period Norms","text":"In India, the standard notice period for most roles is 30 to 90 days. For senior roles such as managers and above, 60 to 90 days is common. Under the Industrial Employment (Standing Orders) Act 1946, the probation period is typically 3 months, extendable to 6 months. For IT sector employees, 60 to 90 day notice periods are standard. Notice periods exceeding 90 days should be scrutinized. The notice period must be reciprocal unless there is a strong business justification.","act_name":"Industrial Employment (Standing Orders) Act 1946","act_section":"Clause 13","jurisdiction":"India","document_type_relevance":"employment_contract","risk_relevance":"medium"},
  {"id":"employment_002","category":"employment_law","title":"Non-Compete Clause Enforceability","text":"Non-compete clauses in India are generally considered unenforceable after the termination of employment. Under Section 27 of the Indian Contract Act 1872, any agreement that restrains a person from exercising a lawful profession, trade, or business is void to that extent. Courts have consistently held that post-employment non-compete restrictions are contrary to public policy. However, non-compete clauses during the period of employment are enforceable.","act_name":"Indian Contract Act 1872","act_section":"Section 27","jurisdiction":"India","document_type_relevance":"employment_contract,nda","risk_relevance":"medium"},
  {"id":"employment_003","category":"employment_law","title":"Gratuity Entitlement","text":"Under the Payment of Gratuity Act 1972, every employee who has completed 5 or more years of continuous service is entitled to gratuity. The formula is: 15 days salary for every completed year of service, calculated as (Last drawn salary x 15) divided by 26. The maximum gratuity payable is capped at Rs 20 lakh. Gratuity is a statutory right and cannot be waived by any contractual provision.","act_name":"Payment of Gratuity Act 1972","act_section":"Section 4","jurisdiction":"India","document_type_relevance":"employment_contract","risk_relevance":"low"},
  {"id":"employment_004","category":"employment_law","title":"Probation Period Rules","text":"Indian employment law does not prescribe a fixed maximum probation period, but the typical practice is 3 to 6 months. Under the Industrial Employment (Standing Orders) Act 1946 for covered establishments, the probation period is typically 3 months, extendable to 6 months. During probation, employers generally have broader discretion to terminate employment. However, termination during probation must still be for valid reasons and cannot be arbitrary or discriminatory.","act_name":"Industrial Employment (Standing Orders) Act 1946","act_section":"Clause 4","jurisdiction":"India","document_type_relevance":"employment_contract","risk_relevance":"medium"},
  {"id":"employment_005","category":"employment_law","title":"NDA Scope and Enforceability","text":"Non-Disclosure Agreements (NDAs) in Indian employment contracts are generally enforceable to the extent they protect legitimate business interests such as trade secrets, client lists, and proprietary technology. NDAs must define the confidential information with reasonable specificity. An overly broad NDA that prevents an employee from using their general skills and knowledge acquired during employment is unreasonable and may be challenged. NDAs are enforceable during employment and for a reasonable time after, typically 1 to 2 years.","act_name":"Indian Contract Act 1872","act_section":"Section 10","jurisdiction":"India","document_type_relevance":"employment_contract,nda","risk_relevance":"medium"},
  {"id":"employment_006","category":"employment_law","title":"PF and ESI Obligations","text":"Under the Employees Provident Fund and Miscellaneous Provisions Act 1952, employers with 20 or more employees must enroll eligible employees in the PF scheme. The current PF contribution rate is 12 percent of basic salary from both employer and employee. Under the Employees State Insurance Act 1948, employers with 10 or more employees must provide ESI coverage for employees earning up to Rs 21,000 per month. ESI contributions are 3.25 percent from the employer and 0.75 percent from the employee.","act_name":"Employees Provident Fund and Miscellaneous Provisions Act 1952","act_section":"Section 6","jurisdiction":"India","document_type_relevance":"employment_contract","risk_relevance":"low"},
  {"id":"employment_007","category":"employment_law","title":"Wrongful Termination","text":"In India, the grounds and process for terminating employment vary depending on whether the employee is a workman under the Industrial Disputes Act 1947 or a managerial employee. Workmen in establishments with 100 or more employees cannot be retrenched without government permission and must receive retrenchment compensation. For other employees, employment contracts typically include termination provisions with notice or payment in lieu of notice. Termination without following the contractual process or for discriminatory reasons can be challenged in Labor Courts.","act_name":"Industrial Disputes Act 1947","act_section":"Section 25F","jurisdiction":"India","document_type_relevance":"employment_contract","risk_relevance":"high"},
  {"id":"employment_008","category":"employment_law","title":"Intellectual Property Assignment","text":"Employment contracts in India commonly include clauses assigning intellectual property created by the employee during the course of employment to the employer. Under the Copyright Act 1957, works created by an employee in the course of their employment are owned by the employer unless otherwise agreed. Assignment clauses that extend to works created outside working hours and unrelated to employment are considered overreaching and may be partially unenforceable.","act_name":"Copyright Act 1957","act_section":"Section 17","jurisdiction":"India","document_type_relevance":"employment_contract,nda","risk_relevance":"medium"},
  {"id":"contract_001","category":"contract_law","title":"What Makes a Contract Valid in India","text":"Under the Indian Contract Act 1872, a valid contract requires: an offer, acceptance, lawful consideration, parties competent to contract, free consent, and a lawful object. A contract is void if it is based on unlawful consideration, involves mistake of fact, or restrains legal proceedings. A contract is voidable if consent was obtained through coercion, undue influence, fraud, or misrepresentation. Both parties must be of legal age (18 years or above) and of sound mind.","act_name":"Indian Contract Act 1872","act_section":"Section 10","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract,nda","risk_relevance":""},
  {"id":"contract_002","category":"contract_law","title":"Void and Voidable Clauses","text":"Under the Indian Contract Act 1872, certain types of contractual clauses are void and unenforceable regardless of what the parties agree. These include: clauses that restrain marriage, clauses in restraint of trade or lawful profession (with limited exceptions), clauses that restrict legal proceedings, and wagering agreements. A void clause does not invalidate the entire contract unless the contract is indivisible from the void clause. Courts in India can strike down unconscionable or unreasonable clauses even in commercial contracts.","act_name":"Indian Contract Act 1872","act_section":"Sections 26-30","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract,nda","risk_relevance":"high"},
  {"id":"contract_003","category":"contract_law","title":"Penalty and Liquidated Damages Clauses","text":"Indian courts draw a distinction between genuine pre-estimates of damage (liquidated damages) and penalties. Under Section 74 of the Indian Contract Act 1872, a party that suffers from a breach of contract is entitled to reasonable compensation regardless of whether a specific sum is named in the contract. Indian courts will reduce penalty clauses to reasonable compensation if the stipulated sum is grossly disproportionate to the actual loss suffered. Penalty clauses must be proportionate to the breach.","act_name":"Indian Contract Act 1872","act_section":"Section 74","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract","risk_relevance":"high"},
  {"id":"contract_004","category":"contract_law","title":"Arbitration Clauses","text":"Arbitration clauses require parties to resolve disputes through private arbitration rather than courts. Under the Arbitration and Conciliation Act 1996, arbitration agreements are generally enforceable and courts will refer disputes to arbitration when a valid arbitration clause exists. Arbitration can be more expensive than small claims court proceedings. Clauses specifying arbitration in a city different from where the agreement is being performed create practical difficulty and cost.","act_name":"Arbitration and Conciliation Act 1996","act_section":"Section 7","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract,nda","risk_relevance":"medium"},
  {"id":"contract_005","category":"contract_law","title":"Indemnification Clauses","text":"Indemnification clauses require one party to compensate the other for losses arising from specified events. Under Section 124 of the Indian Contract Act 1872, a contract of indemnity is valid and enforceable. However, overly broad indemnification clauses that require one party to indemnify the other for losses arising from the other party's own negligence or misconduct are considered unreasonable. Unlimited indemnification obligations create unbounded financial risk.","act_name":"Indian Contract Act 1872","act_section":"Section 124","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract,nda","risk_relevance":"high"},
  {"id":"contract_006","category":"contract_law","title":"Unilateral Amendment Rights","text":"Clauses that allow one party to unilaterally change the terms of a contract without the other party's consent are potentially void under Indian contract law. A valid contract requires mutual agreement, and unilateral changes to material terms without consent violate the principle of mutual assent. Courts in India have struck down clauses that give employers the right to unilaterally change pay, job roles, or other material terms without the employee's agreement.","act_name":"Indian Contract Act 1872","act_section":"Section 2","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract","risk_relevance":"high"},
  {"id":"risky_001","category":"risky_clauses","title":"One-Sided Termination Rights","text":"A one-sided termination clause gives only one party (typically the landlord or employer) the right to terminate the agreement with short or no notice, while requiring the other party to give a longer notice period. This asymmetry creates significant risk for the weaker party. In rental agreements, a landlord who can terminate with 7 days notice while requiring 60 days notice from the tenant has disproportionate control. Such clauses should be resisted or negotiated to create equivalent termination rights for both parties.","act_name":"Indian Contract Act 1872","act_section":"General Contract Principles","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract","risk_relevance":"high"},
  {"id":"risky_002","category":"risky_clauses","title":"Vague and Undefined Penalty Clauses","text":"Penalty clauses that are vague, undefined, or leave the calculation of damages to the other party's discretion are particularly risky. Examples include: damages described as 'all costs and losses suffered' without a cap, penalties described as 'such amount as determined by the landlord', or indemnification for 'any loss howsoever caused'. These open-ended penalty provisions create unlimited financial exposure. Any penalty clause should specify the triggering event precisely, the method of calculation, and a maximum cap on liability.","act_name":"Indian Contract Act 1872","act_section":"Section 74","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract,nda","risk_relevance":"high"},
  {"id":"risky_003","category":"risky_clauses","title":"Waiver of Legal Rights Clauses","text":"Some contracts contain clauses where one party agrees to waive their right to sue, to file consumer complaints, or to approach any regulatory authority. Under Indian law, clauses that seek to waive statutory rights or rights available under consumer protection laws are generally void and unenforceable. A tenant cannot contractually waive their rights under the Model Tenancy Act, and an employee cannot waive their rights to PF, ESI, or gratuity. Clauses stating that the signing party agrees not to approach any court or authority for any reason are extremely aggressive and legally questionable.","act_name":"Indian Contract Act 1872","act_section":"Section 28","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract,nda","risk_relevance":"high"},
  {"id":"risky_004","category":"risky_clauses","title":"Excessive Forfeiture Clauses","text":"Forfeiture clauses specify circumstances in which deposited money will be forfeited entirely rather than returned. While some forfeiture clauses are standard (for example, forfeiting one month's rent if the tenant breaks the lock-in period), clauses that forfeit the entire security deposit for minor breaches or that allow forfeiture at the landlord's discretion are considered aggressive. Under Indian law, forfeiture provisions must bear a reasonable relationship to the actual loss suffered.","act_name":"Indian Contract Act 1872","act_section":"Section 74","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":"high"},
  {"id":"risky_005","category":"risky_clauses","title":"Sweeping NDA Clauses","text":"Non-Disclosure Agreements with overly broad confidentiality clauses pose significant risk. Problem clauses include: defining confidential information as everything shared without requiring any marking as confidential, covering information that is publicly available or independently developed, preventing disclosure to legal advisors, and covering information for an unlimited duration. A reasonable NDA should define confidential information specifically, exclude public information, allow disclosure for legal compliance, and have a reasonable time limit of 2 to 5 years.","act_name":"Indian Contract Act 1872","act_section":"Section 27","jurisdiction":"India","document_type_relevance":"nda,employment_contract","risk_relevance":"high"},
  {"id":"rights_001","category":"rights_remedies","title":"Consumer Forum Remedies","text":"The Consumer Protection Act 2019 provides significant remedies to consumers in India, including for housing-related disputes. A tenant whose security deposit is wrongfully withheld may have recourse to Consumer Forums. Complaints can be filed in District Consumer Disputes Redressal Commissions for claims up to Rs 1 crore. The complaint must be filed within 2 years of the cause of action.","act_name":"Consumer Protection Act 2019","act_section":"Section 35","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract","risk_relevance":""},
  {"id":"rights_002","category":"rights_remedies","title":"Civil Suit for Contract Breach","text":"Any party to a contract in India can file a civil suit for breach of contract in an appropriate Civil Court. The relief available includes damages for the loss suffered, specific performance of the contract, and injunctions to prevent ongoing breach. A civil suit must be filed within 3 years of the breach under the Limitation Act 1963. Before filing a civil suit, sending a formal legal notice to the defaulting party is advisable.","act_name":"Code of Civil Procedure 1908","act_section":"Section 9","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract,nda","risk_relevance":""},
  {"id":"rights_003","category":"rights_remedies","title":"Approaching the Rent Authority","text":"Under the Model Tenancy Act 2021, state governments are required to establish Rent Authorities to resolve disputes between landlords and tenants. Tenants can approach the Rent Authority for issues including: unlawful eviction attempts, wrongful withholding of security deposits, landlord harassment, unauthorized rent increases, and failure to carry out essential repairs. The Rent Authority is intended to be a faster and more accessible dispute resolution mechanism than civil courts.","act_name":"Model Tenancy Act 2021","act_section":"Chapter III","jurisdiction":"India","document_type_relevance":"rental_agreement","risk_relevance":""},
  {"id":"rights_004","category":"rights_remedies","title":"Labor Court Remedies","text":"Employees in India have access to multiple forums for employment disputes. Labor Courts and Industrial Tribunals handle disputes regarding wrongful termination, non-payment of dues, and unfair labor practices for workmen covered under the Industrial Disputes Act 1947. For managerial and senior employees not covered under the Industrial Disputes Act, Civil Courts may have jurisdiction. The Payment of Wages Act 1936 provides fast-track remedies for non-payment of wages through Labor Commissioners.","act_name":"Industrial Disputes Act 1947","act_section":"Section 2A","jurisdiction":"India","document_type_relevance":"employment_contract","risk_relevance":""},
  {"id":"rights_005","category":"rights_remedies","title":"Legal Notice as First Step","text":"Before filing any legal complaint or court case in India, it is advisable and sometimes mandatory to send a formal legal notice to the other party. A legal notice puts the other party on formal notice of your grievance and demands specific action within a specified time period (typically 15 to 30 days). Sending a legal notice through an advocate adds weight to the communication and demonstrates seriousness. Many disputes are resolved at the legal notice stage without requiring court proceedings.","act_name":"Code of Civil Procedure 1908","act_section":"Order 7","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract,nda","risk_relevance":""},
  {"id":"general_001","category":"contract_law","title":"Importance of Reading Before Signing","text":"Under Indian contract law, a person who signs a contract is generally bound by its terms even if they did not read it. Claims of not having read or understood the document are generally not a defense to enforcement unless there was fraud, misrepresentation, or undue influence. This makes it critically important to read every clause of a contract before signing. Once a contract is signed, changing its terms requires the agreement of both parties.","act_name":"Indian Contract Act 1872","act_section":"Section 10","jurisdiction":"India","document_type_relevance":"rental_agreement,employment_contract,nda,property_document","risk_relevance":"high"},
]

pathlib.Path('data').mkdir(exist_ok=True)
with open('data/legal_knowledge_base.json','w',encoding='utf-8') as f:
    json.dump(kb, f, indent=2, ensure_ascii=False)
print(f'Written {len(kb)} entries to data/legal_knowledge_base.json')
